## n8nワークフローJSON（完全版）

以下は「記事企画収集→下書き生成→X告知」を自動化するn8nワークフローのエクスポートJSONだ。n8nの「Import from JSON」でそのまま読み込める。

```json
{
  "name": "Note Article Auto Pipeline",
  "nodes": [
    {
      "id": "trigger",
      "name": "Schedule Trigger",
      "type": "n8n-nodes-base.scheduleTrigger",
      "parameters": {
        "rule": { "interval": [{ "field": "cronExpression", "expression": "0 21 * * 0" }] }
      },
      "position": [240, 300]
    },
    {
      "id": "rss",
      "name": "RSS Feed Reader",
      "type": "n8n-nodes-base.rssFeedRead",
      "parameters": {
        "url": "https://feeds.feedburner.com/oreilly/radar"
      },
      "position": [460, 300]
    },
    {
      "id": "model-router",
      "name": "Model Router",
      "type": "n8n-nodes-base.function",
      "parameters": {
        "functionCode": "// 上記テンプレート5のコードをここに貼り付け"
      },
      "position": [680, 300]
    },
    {
      "id": "claude-ideation",
      "name": "Claude: Article Ideation",
      "type": "@n8n/n8n-nodes-langchain.lmChatAnthropic",
      "parameters": {
        "model": "={{ $json.model }}",
        "messages": {
          "values": [{
            "role": "user",
            "content": "上記テンプレート3のプロンプトをここに貼り付け（変数は{{ $json.title }}形式）"
          }]
        }
      },
      "position": [900, 300]
    },
    {
      "id": "notion-save",
      "name": "Save to Notion",
      "type": "n8n-nodes-base.notion",
      "parameters": {
        "operation": "create",
        "databaseId": "YOUR_NOTION_DB_ID",
        "properties": {
          "Title": { "title": [{ "text": { "content": "={{ $json.title }}" } }] },
          "Hook": { "rich_text": [{ "text": { "content": "={{ $json.hook }}" } }] },
          "Status": { "select": { "name": "Draft" } }
        }
      },
      "position": [1120, 300]
    }
  ],
  "connections": {
    "Schedule Trigger": { "main": [[{ "node": "RSS Feed Reader", "type": "main", "index": 0 }]] },
    "RSS Feed Reader": { "main": [[{ "node": "Model Router", "type": "main", "index": 0 }]] },
    "Model Router": { "main": [[{ "node": "Claude: Article Ideation", "type": "main", "index": 0 }]] },
    "Claude: Article Ideation": { "main": [[{ "node": "Save to Notion", "type": "main", "index": 0 }]] }
  }
}
```

`YOUR_NOTION_DB_ID`を自分のNotionデータベースIDに差し替えるだけで動く。

